            'image' => '/images/',
            'uri' => 'https://example.com',
            'canonical' => '/page',
            'manifest' => '/manifest.json',
            'script' => [
                'scheme' => 'var customScheme = true;'
            ]
        ];

        // Mock the Head object to avoid actual HTML generation
        $head->method('build')->willReturn('<head></head>');
        
        // We can't easily test the method chain directly without a more complex setup
        // But we'll make sure it doesn't error
        $result = HeadGenerate::autoGenerate($head, $option, $data);
        
        $this->assertIsString($result);
    }

